using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class UserPreferredStoreConfiguration : IEntityTypeConfiguration<UserPreferredStore>{public void Configure(EntityTypeBuilder<UserPreferredStore> builder){builder.ToTable("user_preferred_stores");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("preferred_store_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.CustomStoreName).HasMaxLength(100);builder.Property(e => e.GooglePlaceId).HasMaxLength(200);builder.Property(e => e.VisitFrequency).HasMaxLength(30);builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.StoreCategory).WithMany().HasForeignKey(e => e.StoreCategoryId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.StoreCategoryId }).IsUnique();}}
